import{_ as t,o,c as i,ae as s}from"./chunks/framework.B6gjLfeO.js";const v=JSON.parse('{"title":"Add and Manage Test Devices (New)","description":"","frontmatter":{"title":"Add and Manage Test Devices (New)","slug":"add-and-manage-test-devices-new"},"headers":[],"relativePath":"account-hub/add-and-manage-test-devices-new.md","filePath":"account-hub/add-and-manage-test-devices-new.md"}'),n={name:"account-hub/add-and-manage-test-devices-new.md"};function a(r,e,d,l,c,u){return o(),i("div",null,[...e[0]||(e[0]=[s('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>To easily test your campaign setup, we recommend you first add a test device to your Branch account. Doing so tells Branch servers that resulting conversions from said device are for testing purposes only; i.e. these conversions won&#39;t be considered normal traffic and therefore not be treated as such.</p><p>As Branch only allows one install event per unique device to ever be measured and stored, if you don&#39;t first add a test device, you&#39;ll only be able to test the install conversion event once ever.</p><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this page yet?</p><p>The Testing &amp; Monitoring page is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p></div><h2 id="supported-device-ids" tabindex="-1">Supported device IDs <a class="header-anchor" href="#supported-device-ids" aria-label="Permalink to &quot;Supported device IDs&quot;">​</a></h2><p>To identify your device as a test device within Branch, you need to provide one of the following device IDs:</p><ul><li><strong>Android</strong>: Google Advertising ID (GAID)</li><li><strong>iOS</strong>: Identifier for Advertisers (IDFA)</li></ul><p><strong>Use Branch&#39;s Device ID Finder App</strong></p><p>If you don&#39;t know how to access your device&#39;s IDs, you can use Branch&#39;s Device ID Finder app to easily see your device&#39;s ID.</p><ul><li>Get the Android App</li><li>Get the iOS App</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><ul><li>You can add up to 50 test devices per app in Branch.</li><li>Any user can add a device for testing; however, you must have Edit access to remove a test device.</li><li>The test device is specific to the app you add it under. If you use it to test other apps, Branch will treat it like live traffic and it will be attributed and used for downstream analytics.</li><li>These test devices will work in both the live and test environment. You only need to add it once.</li></ul></div><p>To ensure you can use your device to test:</p><ol><li><p>Under <strong>Configuration</strong>, select <strong>Testing &amp; Monitoring &gt; Test Devices</strong>.</p></li><li><p>Select <strong>Add device</strong>.</p></li><li><p>In the <strong>Add test device</strong> modal, provide the following:</p><ul><li><strong>Device name:</strong> Choose a name to help you recognize this device.</li><li><strong>Platform:</strong> Select the platform for your test device.</li><li><strong>Device ID:</strong> Enter a Device ID in IDFA format for iOS or GAID format for Android.</li></ul></li><li><p>Select <strong>Add device</strong>.</p></li></ol><h2 id="refresh-your-test-device" tabindex="-1">Refresh your test device <a class="header-anchor" href="#refresh-your-test-device" aria-label="Permalink to &quot;Refresh your test device&quot;">​</a></h2><p>If you need to test the install event more than once, you need to refresh your test device after each install attempt. Not doing so results in the next install attempt being marked as <code>reinstall</code>.</p><p>To refresh your test device:</p><ol><li>On the <strong>Test Devices</strong> tab, find the test device you want to refresh and select the three-dot icon.</li><li>Select <strong>Refresh device</strong>.</li></ol><h2 id="delete-a-test-device" tabindex="-1">Delete a test device <a class="header-anchor" href="#delete-a-test-device" aria-label="Permalink to &quot;Delete a test device&quot;">​</a></h2><p>To remove a test device from your account:</p><ol><li>On the <strong>Test Devices</strong> tab, find the test device you want to delete and select the three-dot icon.</li><li>Select <strong>Delete device</strong>.</li></ol>',20)])])}const p=t(n,[["render",a]]);export{v as __pageData,p as default};
